/// <summary>
/// Extension class of <c>PSAQuotationsDP</c> for text block management
/// </summary>
[ExtensionOf(classStr(PSAQuotationsDP))]
final class FWFTextBlockPSAQuotationsDP_Extension
{
}

Method.Source:
public void insertPSAQuotationsTmp()
{
    next insertPSAQuotationsTmp();

    FWFTextBlockReportTextInit textBlockReportTextInit = FWFTextBlockReportTextInit::newParameters(this.m_tPSAQuotationsTmp, this.custQuotationJour);

    textBlockReportTextInit.insTexts();
    textBlockReportTextInit.parmSource(this.custQuotationTransTmp);
    textBlockReportTextInit.insLineTexts();
}

public void insertPSAQuotationsConfirmTmp()
{
    next insertPSAQuotationsConfirmTmp();

    FWFTextBlockReportTextInit textBlockReportTextInit = FWFTextBlockReportTextInit::newParameters(this.m_tPSAQuotationsTmp, this.custQuotationConfirmJour);

    textBlockReportTextInit.insTexts();
    textBlockReportTextInit.parmSource(this.custQuotationConfirmTransTmp);
    textBlockReportTextInit.insLineTexts();
}
